   }
   ```

5. **`buildWhereParams(where, model, fkFields)`** -- Builds a parameterized WHERE clause and params object. Returns `{ clause: string, params: Record<string, unknown> }`.
   ```typescript
   // Input: [{ field: "email", value: "a@b.com", operator: "eq" }, { field: "userId", value: "abc", operator: "eq" }]
   // Output: { clause: "email = $w0 AND userId = $w1", params: { w0: "a@b.com", w1: RecordId("user", "abc") } }
   ```
   Operator mapping:
   - `eq` -> `=`
   - `ne` -> `!=`
   - `gt` -> `>`
   - `lt` -> `<`
   - `in` -> `IN`
   - `contains` -> `CONTAINS`
   - `starts_with` -> `string::starts_with(field, $param)`
   - `ends_with` -> `string::ends_with(field, $param)`

**Method implementations (pseudocode):**

```typescript
create: async ({ model, data }) => {
  const fkFields = fkFieldsMap.get(model) ?? new Map();
  const id = data.id as string;
  const record = new RecordId(model, id);
  const content = transformInput(data, model, fkFields); // strips id, converts FKs

  const [result] = await surreal
    .query<[Record<string, unknown>[]]>(
      "CREATE $record CONTENT $content RETURN AFTER;",
      { record, content },
    )
    .collect<[Record<string, unknown>[]]>();

  if (!result[0]) throw new Error(`Failed to create ${model}`);
  return transformOutput(result[0]);
},

findOne: async ({ model, where }) => {
  const fkFields = fkFieldsMap.get(model) ?? new Map();
  const { clause, params } = buildWhereParams(where, model, fkFields);

  const [results] = await surreal
    .query<[Record<string, unknown>[]]>(
      `SELECT * FROM ${model} WHERE ${clause} LIMIT 1;`,
      params,
    )
    .collect<[Record<string, unknown>[]]>();

  const record = results[0];
  if (!record) return undefined; // project convention: no null
  return transformOutput(record);
},

findMany: async ({ model, where, limit, offset, sortBy }) => {
  const fkFields = fkFieldsMap.get(model) ?? new Map();
  let query = `SELECT * FROM ${model}`;
  let params: Record<string, unknown> = {};

  if (where && where.length > 0) {
    const w = buildWhereParams(where, model, fkFields);
    query += ` WHERE ${w.clause}`;
    params = w.params;
  }
  if (sortBy) {
    query += ` ORDER BY ${sortBy.field} ${sortBy.direction.toUpperCase()}`;
  }
  if (limit !== undefined) {
    query += ` LIMIT ${Number(limit)}`;
  }
  if (offset !== undefined) {
    query += ` START ${Number(offset)}`;
  }

  const [results] = await surreal
    .query<[Record<string, unknown>[]]>(query + ";", params)
    .collect<[Record<string, unknown>[]]>();

  return (results ?? []).map(transformOutput);
},

update: async ({ model, where, update: updateData }) => {
  const fkFields = fkFieldsMap.get(model) ?? new Map();
  const { clause, params } = buildWhereParams(where, model, fkFields);
  const content = transformInput(updateData, model, fkFields);

  const [results] = await surreal
    .query<[Record<string, unknown>[]]>(
      `UPDATE ${model} MERGE $data WHERE ${clause};`,
      { ...params, data: content },
    )
    .collect<[Record<string, unknown>[]]>();

  if (!results[0]) throw new Error(`Failed to update ${model}`);
  return transformOutput(results[0]);
},

delete: async ({ model, where }) => {
  const fkFields = fkFieldsMap.get(model) ?? new Map();
  const { clause, params } = buildWhereParams(where, model, fkFields);
  await surreal.query(`DELETE FROM ${model} WHERE ${clause};`, params);
},

count: async ({ model, where }) => {
  const fkFields = fkFieldsMap.get(model) ?? new Map();
  let query: string;
  let params: Record<string, unknown> = {};

  if (where && where.length > 0) {
    const w = buildWhereParams(where, model, fkFields);
    query = `SELECT count() FROM ${model} WHERE ${w.clause} GROUP ALL;`;
    params = w.params;
  } else {
    query = `SELECT count() FROM ${model} GROUP ALL;`;
  }

  const [results] = await surreal
    .query<[Array<{ count: number }>]>(query, params)
    .collect<[Array<{ count: number }>]>();

  return results[0]?.count ?? 0;
},
```

**Important note on `null` vs `undefined`:** better-auth's `findOne` is typed to return `null` when no record is found. The `createAdapterFactory` wrapper handles the conversion from the adapter's return value. The adapter can safely return `undefined` (matching project convention) and the factory will translate it to `null` for better-auth's internal consumption. However, if the factory does NOT handle this, we may need to return `null` specifically in `findOne` as an exception to the project's no-null rule, since this is at the library boundary.

