 33→            const dbColumn = getFieldName({ model: defaultModel, field: defaultField });
 34→            const refDbTable = getModelName(fieldAttr.references.model);
 35→            tableFks.set(dbColumn, refDbTable);
 36→          }
 37→        }
 38→        if (tableFks.size > 0) {
 39→          fkMap.set(dbTable, tableFks);
 40→        }
 41→      }
 42→
 43→      function getFkTable(model: string, field: string): string | undefined {
 44→        return fkMap.get(model)?.get(field);
 45→      }
 46→
 47→      /** Convert string FK values to RecordId for writes/where clauses. */
 48→      function toRecordId(model: string, field: string, value: unknown): unknown {
 49→        if (value === null || value === undefined) return value;
 50→        if (field === "id") return new RecordId(model, value as string);
 51→        const refTable = getFkTable(model, field);
 52→        if (refTable && typeof value === "string") return new RecordId(refTable, value);
 53→        return value;
 54→      }
 55→
 56→      /** Convert RecordId objects back to plain strings for the factory. */
 57→      function fromRecord(value: unknown): unknown {
 58→        if (value instanceof RecordId) return value.id as string;
 59→        return value;
 60→      }
 61→
 62→      function transformOutputRecord(record: Record<string, unknown>): Record<string, unknown> {
 63→        const out: Record<string, unknown> = {};
