 74→        stripId: boolean,
 75→      ): Record<string, unknown> {
 76→        const content: Record<string, unknown> = {};
 77→        for (const [key, value] of Object.entries(data)) {
 78→          if (stripId && key === "id") continue;
 79→          content[key] = toRecordId(model, key, value);
 80→        }
 81→        return content;
 82→      }
 83→
 84→      /** Build parameterized WHERE clause from CleanedWhere[]. */
 85→      function buildWhere(
 86→        where: CleanedWhere[],
 87→        model: string,
 88→      ): { clause: string; params: Record<string, unknown> } {
 89→        const parts: string[] = [];
 90→        const params: Record<string, unknown> = {};
 91→
 92→        for (let i = 0; i < where.length; i++) {
 93→          const w = where[i];
 94→          const paramKey = `w${i}`;
 95→          const value = toRecordId(model, w.field, w.value);
 96→          params[paramKey] = value;
 97→
 98→          const connector = i > 0 ? ` ${w.connector} ` : "";
 99→          let expr: string;
100→
101→          switch (w.operator) {
102→            case "eq":
103→              if (value === null) {
104→                expr = `${w.field} IS NONE`;
105→                delete params[paramKey];
106→              } else {
107→                expr = `${w.field} = $${paramKey}`;
108→              }
109→              break;
110→            case "ne":
111→              if (value === null) {
112→                expr = `${w.field} IS NOT NONE`;
113→                delete params[paramKey];
114→              } else {
115→                expr = `${w.field} != $${paramKey}`;
116→              }
117→              break;
118→            case "gt":
119→              expr = `${w.field} > $${paramKey}`;
120→              break;
121→            case "gte":
122→              expr = `${w.field} >= $${paramKey}`;
123→              break;
124→            case "lt":
125→              expr = `${w.field} < $${paramKey}`;
126→              break;
127→            case "lte":
128→              expr = `${w.field} <= $${paramKey}`;
129→              break;
130→            case "in":
131→              expr = `${w.field} IN $${paramKey}`;
132→              break;
133→            case "not_in":
134→              expr = `${w.field} NOT IN $${paramKey}`;
135→              break;
136→            case "contains":
137→              expr = `${w.field} CONTAINS $${paramKey}`;
138→              break;
139→            case "starts_with":
140→              expr = `string::starts_with(${w.field}, $${paramKey})`;
141→              break;
142→            case "ends_with":
143→              expr = `string::ends_with(${w.field}, $${paramKey})`;
144→              break;
145→            default:
146→              expr = `${w.field} = $${paramKey}`;
147→          }
148→
149→          parts.push(`${connector}${expr}`);
150→        }
151→
152→        return { clause: parts.join(""), params };
153→      }
154→
155→      return {
156→        create: async ({ model, data }) => {
157→          const id = data.id as string;
158→          const record = new RecordId(model, id);
159→          const content = transformInputRecord(data, model, true);
160→
161→          const [result] = await surreal.query<[Record<string, unknown>[]]>(
162→            `CREATE $record CONTENT $content RETURN AFTER;`,
163→            { record, content },
164→          );
165→
166→          if (!result?.[0]) throw new Error(`Failed to create ${model} record`);
167→          return transformOutputRecord(result[0]) as any;
168→        },
169→
170→        findOne: async ({ model, where }) => {
171→          const { clause, params } = buildWhere(where, model);
172→
173→          const [results] = await surreal.query<[Record<string, unknown>[]]>(
174→            `SELECT * FROM ${model} WHERE ${clause} LIMIT 1;`,
