  const sql = readFileSync(join(migrationsDir, file), "utf8");
  try {
    await surreal.query(sql);
    console.log(`Migration ${file}: OK`);
  } catch (e) {
    console.error(`Migration ${file}: FAILED - ${e.message}`);
  }
}

// Cleanup
await surreal.query(`REMOVE DATABASE ${db};`);
await surreal.query(`REMOVE NAMESPACE ${ns};`);
await surreal.close();
