cat << 'SCRIPT' | bun run -
import { readFileSync } from "node:fs";
import { join } from "node:path";
import { Surreal } from "surrealdb";

const surreal = new Surreal();
await surreal.connect("ws://127.0.0.1:8000/rpc");
await surreal.signin({ username: "root", password: "root" });

const ns = `debug2_${Date.now()}`;
const db = `test_${Math.floor(Math.random() * 100000)}`;

await surreal.query(`DEFINE NAMESPACE ${ns};`);
await surreal.use({ namespace: ns });
await surreal.query(`DEFINE DATABASE ${db};`);
await surreal.use({ namespace: ns, database: db });

// Apply schema only (no migrations)
const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
await surreal.query(schemaSql);
console.log("Schema applied OK");

// Now try migration 0010 specifically
const m10 = readFileSync(join(process.cwd(), "schema", "migrations", "0010_better_auth_tables.surql"), "utf8");
try {
  await surreal.query(m10);
  console.log("Migration 0010: OK");
} catch (e) {
  console.error("Migration 0010 FAILED:", e.message);

  // Try each statement individually
  const statements = m10.replace(/BEGIN TRANSACTION;/, '').replace(/COMMIT TRANSACTION;/, '').split(';').filter(s => s.trim());
  for (const stmt of statements) {
    const s = stmt.trim();
    if (!s) continue;
    try {
      await surreal.query(s + ";");
      console.log("  OK:", s.substring(0, 60));
    } catch (e2) {
      console.error("  FAIL:", s.substring(0, 60), "-", e2.message);
    }
  }
}

await surreal.query(`REMOVE DATABASE ${db};`);
await surreal.query(`REMOVE NAMESPACE ${ns};`);
await surreal.close();
